    /// <summary>
    /// BomberSquad-specific implementation of the playtest bridge interfaces.
    /// Auto-creates itself when entering Play Mode â€” no manual setup required.
    ///
    /// For other projects: create your own MonoBehaviour implementing IPlaytestGameState
    /// and/or IPlaytestInputReceiver instead of using this class.
    /// </summary>
    [InitializeOnLoad]
    public class BomberSquadPlaytestBridge : MonoBehaviour, IPlaytestGameState, IPlaytestInputReceiver
    {
        private static BomberSquadPlaytestBridge _instance;

        static BomberSquadPlaytestBridge()
        {
            EditorApplication.playModeStateChanged -= OnPlayModeChanged;
            EditorApplication.playModeStateChanged += OnPlayModeChanged;
        }

        private static void OnPlayModeChanged(PlayModeStateChange state)
        {
            if (state == PlayModeStateChange.EnteredPlayMode)
            {
                if (_instance != null) return;

                var go = new GameObject("[McpPlaytest Bridge]");
                go.hideFlags = HideFlags.HideAndDontSave;
                DontDestroyOnLoad(go);
                _instance = go.AddComponent<BomberSquadPlaytestBridge>();
            }
            else if (state == PlayModeStateChange.ExitingPlayMode)
            {
                if (_instance != null)
                {
                    DestroyImmediate(_instance.gameObject);
                    _instance = null;
                }
            }
        }

        // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
        // IPlaytestGameState
        // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

        public JObject QueryFullState()
        {
            var gm = GameManager.instance;
            if (gm == null)
            {
                return new JObject
                {
                    ["success"] = true,
                    ["isPlayMode"] = EditorApplication.isPlaying,
                    ["gameManagerFound"] = false,
                    ["message"] = "GameManager not found. Is a scene with GameManager loaded?"
                };
            }

            var result = new JObject
            {
                ["success"] = true,
                ["isPlayMode"] = EditorApplication.isPlaying,
                ["gameManagerFound"] = true,
                ["currentState"] = gm.currentState.ToString(),
                ["currentRoundNumber"] = gm.currentRoundNumber,
                ["alivePlayerCount"] = gm.GetAlivePlayerCount(),
                ["totalPlayerCount"] = gm.players?.Count ?? 0
            };

            result["players"] = this.BuildPlayersArray(gm);
            result["round"] = this.BuildRoundInfo(gm);
            result["gameMode"] = this.BuildGameModeInfo(gm);

            return result;
        }

        public JObject QueryPlayers()
        {
            var gm = GameManager.instance;
            if (gm == null)
            {
                return new JObject
                {
                    ["success"] = true,
                    ["gameManagerFound"] = false,
                    ["players"] = new JArray()
                };
            }

            return new JObject
            {
                ["success"] = true,
                ["gameManagerFound"] = true,
                ["players"] = this.BuildPlayersArray(gm)
            };
        }

        public JObject QueryRound()
        {
            var gm = GameManager.instance;
            if (gm == null)
            {
                return new JObject
                {
                    ["success"] = true,
                    ["gameManagerFound"] = false
                };
            }

            return new JObject
            {
                ["success"] = true,
                ["gameManagerFound"] = true,
                ["round"] = this.BuildRoundInfo(gm)
            };
        }

        public JObject QueryGameMode()
        {
            var gm = GameManager.instance;
            if (gm == null)
            {
                return new JObject
                {
                    ["success"] = true,
                    ["gameManagerFound"] = false
                };
            }

            return new JObject
            {
                ["success"] = true,
                ["gameManagerFound"] = true,
                ["gameMode"] = this.BuildGameModeInfo(gm)
            };
        }

        private JArray BuildPlayersArray(GameManager gm)
        {
            var playersArray = new JArray();

            if (gm.players == null) return playersArray;

            for (int i = 0; i < gm.players.Count; i++)
            {
                var pd = gm.players[i];
                var playerObj = new JObject
                {
                    ["playerIndex"] = pd.playerIndex,
                    ["score"] = pd.score,
                    ["kills"] = pd.kills,
                    ["deaths"] = pd.deaths,
                    ["suicides"] = pd.suicides,
                    ["isReady"] = pd.isReady
                };

                if (pd.controller != null)
                {
                    var pos = pd.controller.transform.position;
                    playerObj["position"] = new JObject
                    {
                        ["x"] = pos.x,
                        ["y"] = pos.y,
                        ["z"] = pos.z
                    };

                    var currentState = pd.controller.stateMachine?.currentState;
                    playerObj["currentState"] = currentState?.GetType().Name ?? "Unknown";
                    playerObj["isAlive"] = currentState != pd.controller.playerDeathState;
                    playerObj["isActive"] = pd.controller.gameObject.activeSelf;
                }
                else
                {
                    playerObj["position"] = null;
                    playerObj["currentState"] = "NoController";
                    playerObj["isAlive"] = false;
                    playerObj["isActive"] = false;
                }

                playersArray.Add(playerObj);
            }

            return playersArray;
        }

        private JObject BuildRoundInfo(GameManager gm)
        {
            var roundObj = new JObject
            {
                ["currentRoundNumber"] = gm.currentRoundNumber,
                ["currentState"] = gm.currentState.ToString()
            };

            if (gm.currentRound != null)
            {
                roundObj["elapsedTime"] = gm.currentRound.elapsedTime;
                roundObj["remainingTime"] = gm.currentRound.remainingTime;
            }

            return roundObj;
        }

        private JObject BuildGameModeInfo(GameManager gm)
        {
            if (gm.gameMode == null)
            {
                return new JObject { ["available"] = false };
            }

            var mode = gm.gameMode;
            return new JObject
            {
                ["available"] = true,
                ["modeName"] = mode.modeName,
                ["description"] = mode.description,
                ["numberOfRounds"] = mode.numberOfRounds,
                ["roundDuration"] = mode.roundDuration,
                ["roundStartDelay"] = mode.roundStartDelay,
                ["roundEndDelay"] = mode.roundEndDelay,
                ["pointsPerKill"] = mode.pointsPerKill,
                ["suicidePenalty"] = mode.suicidePenalty,
                ["respawnDelay"] = mode.respawnDelay,
                ["maxPlayers"] = mode.maxPlayers,
                ["useLastManStanding"] = mode.useLastManStanding,
                ["allowMeleeWeapons"] = mode.allowMeleeWeapons,
                ["allowRangedWeapons"] = mode.allowRangedWeapons,
                ["allowThrowWeapons"] = mode.allowThrowWeapons,
                ["allowSpecialAbility"] = mode.allowSpecialAbility
            };
        }

        // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
        // IPlaytestInputReceiver
        // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

        public PlayerInput FindPlayerInput(int playerIndex)
        {
            var controller = this.FindPlayerController(playerIndex);
            if (controller == null) return null;

            return controller.playerInput;
        }

        public JObject SimulateButtonPress(int playerIndex, string action)
        {
            var controller = this.FindPlayerController(playerIndex);
            if (controller == null) return null;

            string fieldName = action switch
            {
                "melee_attack" => "meleeAttackPressed",
                "ranged_attack" => "rangedAttackPressed",
                "throw_attack" => "throwAttackPressed",
                "special_ability" => "specialAbilityPressed",
                _ => null
            };

            if (fieldName == null) return null;

            var field = typeof(PlayerController).GetField($"<{fieldName}>k__BackingField",
                BindingFlags.NonPublic | BindingFlags.Instance);
            if (field != null)
            {
                field.SetValue(controller, true);
                return new JObject
                {
                    ["success"] = true,
                    ["action"] = action,
                    ["playerIndex"] = playerIndex,
                    ["method"] = "reflection"
                };
            }

            return null;
        }

        private PlayerController FindPlayerController(int playerIndex)
        {
            var gm = GameManager.instance;
            if (gm != null && gm.players != null)
            {
                for (int i = 0; i < gm.players.Count; i++)
                {
                    if (gm.players[i].playerIndex == playerIndex && gm.players[i].controller != null)
                    {
                        return gm.players[i].controller;
                    }
                }
            }

            var controllers = Object.FindObjectsByType<PlayerController>(FindObjectsSortMode.None);
            foreach (var ctrl in controllers)
            {
                if (ctrl.playerIndex == playerIndex)
                {
                    return ctrl;
                }
            }

            return null;
        }
    }
}

using UnityEngine.InputSystem;
using Newtonsoft.Json.Linq;

namespace McpPlaytest
{
    /// <summary>
    /// Implement this interface to provide game state information to the MCP Playtest server.
    /// Register your implementation via PlaytestBridge.RegisterGameState().
    /// </summary>
    public interface IPlaytestGameState
    {
        JObject QueryFullState();
        JObject QueryPlayers();
        JObject QueryRound();
        JObject QueryGameMode();
    }

    /// <summary>
    /// Implement this interface to allow the MCP Playtest server to simulate input
    /// on your player controllers. Register via PlaytestBridge.RegisterInputReceiver().
    /// </summary>
    public interface IPlaytestInputReceiver
    {
        PlayerInput FindPlayerInput(int playerIndex);
        JObject SimulateButtonPress(int playerIndex, string action);
    }

    /// <summary>
    /// Static registry for playtest bridge implementations.
    /// Game-specific bridges register themselves here (typically in [InitializeOnLoad] or on play mode enter).
    /// </summary>
    public static class PlaytestBridge
    {
        public static IPlaytestGameState GameState { get; private set; }
        public static IPlaytestInputReceiver InputReceiver { get; private set; }

        public static void RegisterGameState(IPlaytestGameState bridge)
        {
            GameState = bridge;
        }

        public static void RegisterInputReceiver(IPlaytestInputReceiver bridge)
        {
            InputReceiver = bridge;
        }

        public static void Clear()
        {
            GameState = null;
            InputReceiver = null;
        }
    }
}

using Newtonsoft.Json.Linq;

namespace McpPlaytest
{
    public class QueryGameStateTool : PlaytestToolBase
    {
        public QueryGameStateTool()
        {
            this.Name = "query_game_state";
            this.Description = "Query runtime game state: full, players, round, or game_mode";
        }

        public override JObject Execute(JObject parameters)
        {
            var query = parameters["query"]?.ToString() ?? "full";

            var bridge = PlaytestBridge.GameState;
            if (bridge == null)
            {
                return new JObject
                {
                    ["success"] = false,
                    ["error"] = "No IPlaytestGameState registered. Register a bridge via PlaytestBridge.RegisterGameState() to enable game state queries.",
                    ["isPlayMode"] = UnityEditor.EditorApplication.isPlaying
                };
            }

            switch (query)
            {
                case "full":
                    return bridge.QueryFullState();
                case "players":
                    return bridge.QueryPlayers();
                case "round":
                    return bridge.QueryRound();
                case "game_mode":
                    return bridge.QueryGameMode();
                default:
                    return PlaytestSocketHandler.CreateErrorResponse($"Unknown query: {query}. Valid: full, players, round, game_mode", "validation_error");
            }
        }
    }
}

